parameters.body:
={
  "@type": "MessageCard",
  "@context": "http://schema.org/extensions",
  "themeColor": "28A745",
  "summary": "ClickHouse Backup Success",
  "sections": [
    {
      "activityTitle": "✅ **ClickHouse Backup Completed Successfully**",
      "activitySubtitle": "Automated Backup Routine",
      "facts": [
        {
          "name": "Date:",
          "value": "{{ $now.toFormat('yyyy-MM-dd HH:mm:ss') }}"
        },
        {
          "name": "Backup Type:",
          "value": "Full Backup (Sunday)"
        },
        {
          "name": "Target Folder:",
          "value": "backup-{{ $now.toFormat('yyyyMMdd') }}"
        }
      ],
      "markdown": true
    }
  ]
}

={
  "@type": "MessageCard",
  "@context": "http://schema.org/extensions",
  "themeColor": "28A745",
  "summary": "ClickHouse Backup Success",
  "sections": [
    {
      "activityTitle": "✅ **ClickHouse Backup Completed Successfully**",
      "activitySubtitle": "Automated Backup Routine",
      "facts": [
        {
          "name": "Date:",
          "value": "{{ $now.toFormat('yyyy-MM-dd HH:mm:ss') }}"
        },
        {
          "name": "Backup Type:",
          "value": "Incremental Backup"
        },
        {
          "name": "Target Folder:",
          "value": "backup-{{ $now.toFormat('yyyyMMdd') }}"
        }
      ],
      "markdown": true
    }
  ]
}

={
  "@type": "MessageCard",
  "@context": "http://schema.org/extensions",
  "themeColor": "DC3545",
  "summary": "ClickHouse Backup Failed",
  "sections": [
    {
      "activityTitle": "🚨 **ClickHouse Backup FAILED!**",
      "activitySubtitle": "Automated Backup Routine Error",
      "facts": [
        {
          "name": "Failed Node:",
          "value": "{{ $json['execution']['lastNodeExecuted'] }}"
        },
        {
          "name": "Error Message:",
          "value": "{{ $json['error']['message'] }}"
        },
        {
          "name": "Time:",
          "value": "{{ $now.toFormat('yyyy-MM-dd HH:mm:ss') }}"
        }
      ],
      "markdown": true
    }
  ]
}
